  `user_id` int(11) NOT NULL,
  `pokedex_id` int(11) NOT NULL,
  `pokemon_id` varchar(100) NOT NULL,
  `caught` tinyint(1) DEFAULT 0,
  `shiny` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`user_id`,`pokedex_id`,`pokemon_id`),
  KEY `pokemon_id` (`pokemon_id`),
  KEY `user_progress_ibfk_2` (`pokedex_id`),
  CONSTRAINT `user_progress_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `user_progress_ibfk_2` FOREIGN KEY (`pokedex_id`) REFERENCES `pokedex_list` (`id`),
  CONSTRAINT `user_progress_ibfk_3` FOREIGN KEY (`pokemon_id`) REFERENCES `pokemon_forms` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
